120		DisplayMode options.Option = "display_mode"
121		// DisplayModeAlways displays the segment always
122		DisplayModeAlways string = "always"
123		// DisplayModeFiles displays the segment when the current folder contains certain extensions
124		DisplayModeFiles string = "files"
125		// DisplayModeEnvironment displays the segment when the environment has a language's context
126		DisplayModeEnvironment string = "environment"
127		// DisplayModeContext displays the segment when the environment or files is active
128		DisplayModeContext string = "context"
129		// MissingCommandText sets the text to display when the command is not present in the system
130		MissingCommandText options.Option = "missing_command_text"
131		// HomeEnabled displays the segment in the HOME folder or not
132		HomeEnabled options.Option = "home_enabled"
133		// LanguageExtensions the list of extensions to validate
134		LanguageExtensions options.Option = "extensions"
135		// LanguageFolders the list of folders to validate
136		LanguageFolders options.Option = "folders"
137		// Tooling allows enabling additional version fetching tools
138		Tooling options.Option = "tooling"
139	)
140	
141	func (l *Language) getName() string {
142		_, file, _, _ := runtime_.Caller(2)
143		base := filepath.Base(file)
144		return base[:len(base)-3]
145	}
146	
147	func (l *Language) Enabled() bool {
148		l.name = l.getName()
149		// override default extensions if needed
150		l.extensions = l.options.StringArray(LanguageExtensions, l.extensions)
151		l.folders = l.options.StringArray(LanguageFolders, l.folders)
152		inHomeDir := func() bool {
153			return l.env.Pwd() == l.env.Home()
154		}
155	
156		var enabled bool
157	
158		homeEnabled := l.options.Bool(HomeEnabled, l.homeEnabled)
159		if inHomeDir() && !homeEnabled {
160			return false
161		}
162	
163		if len(l.projectFiles) != 0 && l.hasProjectFiles() {
164			enabled = true
165		}
166	
167		if !enabled {
168			// set default mode when not set
169			if l.displayMode == "" {
170				l.displayMode = l.options.String(DisplayMode, DisplayModeFiles)
171			}
172	
173			l.loadLanguageContext()
174	
175			switch l.displayMode {
176			case DisplayModeAlways:
177				enabled = true
178			case DisplayModeEnvironment:
179				enabled = l.inLanguageContext()
180			case DisplayModeFiles:
181				enabled = l.hasLanguageFiles() || l.hasLanguageFolders()
182			case DisplayModeContext:
183				fallthrough
184			default:
185				enabled = l.hasLanguageFiles() || l.hasLanguageFolders() || l.inLanguageContext() || l.hasProjectFiles()
186			}
187		}
188	
189		l.loadTooling()
190	
191		if !enabled || !l.options.Bool(options.FetchVersion, true) {
192			return enabled
193		}
194	
195		err := l.setVersion()
196		if err != nil {
197			l.Error = err.Error()
198		}
199	
200		if l.matchesVersionFile != nil {
201			expected, match := l.matchesVersionFile()
202			if !match {
203				l.Mismatch = true
204				l.Expected = expected
205			}
206		}
207	
208		return enabled
209	}
210	
211	// loadTooling builds the commands list from the tooling map based on the tooling configuration.
212	// Users can override the default tooling via the Tooling option.
213	// This allows specifying which tools should be used to fetch versions
214	// (e.g., "uv" for Python to use UV package manager).
215	func (l *Language) loadTooling() {
216		enabledTools := l.options.StringArray(Tooling, l.defaultTooling)
217		if len(enabledTools) == 0 {
218			return
219		}
220	
221		var commands []*cmd
222		for _, tool := range enabledTools {
223			if command, exists := l.tooling[tool]; exists {
224				commands = append(commands, command)
225			}
226		}
227	
228		l.commands = commands
229	}
230	
231	func (l *Language) hasLanguageFiles() bool {
232		return slices.ContainsFunc(l.extensions, l.env.HasFiles)
233	}
234	
235	func (l *Language) hasProjectFiles() bool {
236		for _, extension := range l.projectFiles {
237			if configPath, err := l.env.HasParentFilePath(extension, false); err == nil {
238				l.projectRoot = configPath
239				return true
240			}
241		}
242	
243		return false
244	}
245	
246	func (l *Language) hasLanguageFolders() bool {
247		return slices.ContainsFunc(l.folders, l.env.HasFolder)
248	}
249	
250	// setVersion parses the version string returned by the command
251	func (l *Language) setVersion() error {
252		var lastError error
253	
254		cacheKey := fmt.Sprintf("version_%s", l.name)
255	
256		if versionCache, OK := cache.Get[Version](cache.Device, cacheKey); OK {
257			l.Version = versionCache
258			return nil
259		}
260	
261		for _, command := range l.commands {
262			versionStr, err := l.runCommand(command)
263			if err != nil {
264				log.Error(err)
265				lastError = err
266				continue
267			}
268	
269			version, err := command.parse(versionStr)
270			if err != nil {
271				log.Error(err)
272				lastError = fmt.Errorf("err parsing info from %s with %s", command.executable, versionStr)
273				continue
274			}
275	
276			l.Version = *version
277			if command.versionURLTemplate != "" {
278				l.versionURLTemplate = command.versionURLTemplate
279			}
280	
281			l.buildVersionURL()
282			l.Executable = command.executable
283	
284			duration := l.options.String(options.CacheDuration, string(cache.NONE))
285			cache.Set(cache.Device, cacheKey, l.Version, cache.Duration(duration))
286	
287			return nil
288		}
289	
290		if lastError != nil {
291			return lastError
292		}
293	
294		return errors.New(l.options.String(MissingCommandText, ""))
295	}
296	
297	func (l *Language) runCommand(command *cmd) (string, error) {
298		if command.getVersion == nil {
299			if !l.env.HasCommand(command.executable) {
300				return "", errors.New(noVersion)
301			}
302	
303			versionStr, err := l.env.RunCommandWithEnv(command.executable, command.envs, command.args...)
304	
305			if exitErr, ok := err.(*runtime.CommandError); ok {
306				l.exitCode = exitErr.ExitCode
307				return "", fmt.Errorf("err executing %s with %v", command.executable, command.args)
308			}
309	
310			return versionStr, nil
311		}
312	
313		versionStr, err := command.getVersion()
314		if err != nil {
315			return "", err
316		}
317	
318		if versionStr == "" {
319			return "", errors.New("no version found")
320		}
321	
322		return versionStr, nil
323	}
324	
325	func (l *Language) loadLanguageContext() {
326		if l.loadContext == nil {
327			return
328		}
329		l.loadContext()
330	}
331	
332	func (l *Language) inLanguageContext() bool {
333		if l.inContext == nil {
334			return false
335		}
336		return l.inContext()
337	}
338	
339	func (l *Language) buildVersionURL() {
340		versionURLTemplate := l.options.String(options.VersionURLTemplate, l.versionURLTemplate)
341		if versionURLTemplate == "" {
342			return
343		}
344	
345		url, err := template.Render(versionURLTemplate, l.Version)
346		if err != nil {
347			return
348		}
349	
350		l.URL = url
351	}
352	
353	func (l *Language) hasNodePackage(name string) bool {
354		packageJSON := l.env.FileContent(fileName)
355	
356		var packageData map[string]any
357		if err := json.Unmarshal([]byte(packageJSON), &packageData); err != nil {
358			return false
359		}
360	
361		dependencies, ok := packageData["dependencies"].(map[string]any)
362		if !ok {
363			return false
364		}
365	
366		if _, exists := dependencies[name]; !exists {
367			return false
368		}
369	
370		return true
371	}
372	
373	func (l *Language) nodePackageVersion(name string) (string, error) {
374		folder := filepath.Join(l.env.Pwd(), "node_modules", name)
375	
376		if !l.env.HasFilesInDir(folder, fileName) {
377			return "", fmt.Errorf("%s not found in %s", fileName, folder)
378		}
