14	func (m *Mojo) Template() string {
15		return " {{ if .Error }}{{ .Error }}{{ else }}{{ if .Venv }}{{ .Venv }} {{ end }}{{ .Full }}{{ end }} "
16	}
17	
18	func (m *Mojo) Enabled() bool {
19		m.extensions = []string{"*.🔥", "*.mojo", "mojoproject.toml"}
20		m.tooling = map[string]*cmd{
21			mojoToolName: {
22				executable: mojoToolName,
23				args:       []string{versionFlagArg},
24				regex:      `(?:mojo (?P<version>((?P<major>[0-9]+).(?P<minor>[0-9]+).(?P<patch>[0-9]+))))`,
25			},
26		}
27		m.defaultTooling = []string{mojoToolName}
28		m.displayMode = m.options.String(DisplayMode, DisplayModeEnvironment)
29		m.Language.loadContext = m.loadContext
30		m.Language.inContext = m.inContext
31	
32		return m.Language.Enabled()
33	}
34	
35	func (m *Mojo) loadContext() {
36		if !m.options.Bool(FetchVirtualEnv, true) {
37			return
38		}
39	
40		// Magic, the official package manager and virtual env manager,
41		// is built on top of pixi: https://github.com/prefix-dev/pixi
42		venv := m.env.Getenv("PIXI_ENVIRONMENT_NAME")
43		if len(venv) > 0 && m.canUseVenvName(venv) {
44			m.Venv = venv
45		}
46	}
47	
48	func (m *Mojo) inContext() bool {
49		return m.Venv != ""
50	}
51	
52	func (m *Mojo) canUseVenvName(name string) bool {
53		defaultNames := []string{defaultStr}
54	
55		if m.options.Bool(options.DisplayDefault, true) ||
56			!slices.Contains(defaultNames, name) {
57			return true
58		}
59	
60		return false
61	}
