22	func (g *Golang) Enabled() bool {
23		g.extensions = []string{"*.go", "go.mod", "go.sum", "go.work", "go.work.sum"}
24		g.tooling = map[string]*cmd{
25			"mod": {
26				regex:      `(?P<version>((?P<major>[0-9]+).(?P<minor>[0-9]+)(.(?P<patch>[0-9]+))?))`,
27				getVersion: g.getVersion,
28			},
29			"go": {
30				executable: "go",
31				args:       []string{versionArg},
32				regex:      `(?:go(?P<version>((?P<major>[0-9]+).(?P<minor>[0-9]+)(.(?P<patch>[0-9]+))?)))`,
33			},
34		}
35		g.defaultTooling = []string{"mod", "go"}
36		g.versionURLTemplate = "https://golang.org/doc/go{{ .Major }}.{{ .Minor }}"
37	
38		return g.Language.Enabled()
