41	// getVersion returns the version of the Go language
42	// It first checks if the go.mod file is present and if it is, it parses the file to get the version
43	// If the go.mod file is not present, it checks if the go.work file is present and if it is, it parses the file to get the version
44	// If neither file is present, it returns an empty string
45	func (g *Golang) getVersion() (string, error) {
46		if g.options.Bool(ParseModFile, false) {
47			return g.parseModFile()
48		}
49	
50		if g.options.Bool(ParseWorkFile, false) {
51			return g.parseWorkFile()
52		}
53	
54		return "", nil
55	}
56	
57	func (g *Golang) parseModFile() (string, error) {
58		gomod, err := g.env.HasParentFilePath("go.mod", false)
59		if err != nil {
60			return "", err
61		}
62	
63		contents := g.env.FileContent(gomod.Path)
64		file, err := modfile.Parse(gomod.Path, []byte(contents), nil)
65		if err != nil {
66			return "", err
67		}
68	
69		if file.Go.Version != "" {
70			return file.Go.Version, nil
71		}
72	
73		// ignore when no version is found in go.mod file
74		return "", nil
75	}
76	
77	func (g *Golang) parseWorkFile() (string, error) {
78		goWork, err := g.env.HasParentFilePath("go.work", false)
79		if err != nil {
80			return "", err
81		}
82	
83		contents := g.env.FileContent(goWork.Path)
84		version, _ := regex.FindStringMatch(`go (\d(\.\d{1,2})?(\.\d{1,2})?)`, contents, 1)
85		if len(version) > 0 {
86			return version, nil
87		}
88	
89		// ignore when no version is found in go.work file
90		return "", nil
91	}
